import { CommandHandler, type ICommandHandler } from "@nestjs/cqrs";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository } from "typeorm";
import { Transactional } from "typeorm-transactional";

import { PaymentStatus } from "../../../../constants/payment-status.ts";
import { PaymentEntity } from "../../payment.entity.ts";
import { CreatePaymentCommand } from "./create-payment.command.ts";

@CommandHandler(CreatePaymentCommand)
export class CreatePaymentHandler
  implements ICommandHandler<CreatePaymentCommand, PaymentEntity>
{
  constructor(
    @InjectRepository(PaymentEntity)
    private readonly paymentRepository: Repository<PaymentEntity>,
  ) {}

  @Transactional()
  async execute(command: CreatePaymentCommand): Promise<PaymentEntity> {
    const { userId, createPaymentDto } = command;

    const payment = this.paymentRepository.create({
      ...createPaymentDto,
      userId,
      status: PaymentStatus.PENDING,
      currency: createPaymentDto.currency || "BTN",
    });

    return this.paymentRepository.save(payment);
  }
}
